sql:
SELECT stability_value 
FROM stability_data 
WHERE stability_data_id = 1;

SELECT duty_cycle_value
FROM duty_cycle_data
WHERE data_point_id = 1;

SELECT AVG(CAST(setting_value AS REAL)) AS average_flow_rate
FROM machine_settings
WHERE setting_name = 'flow rate';
